const body = $json.body || {};
const timestamp = new Date().toISOString();
const datePart = timestamp.slice(0,10).replace(/-/g, '');
const rand = Math.floor(1000 + Math.random() * 9000);
const protocolo = `ECO-${datePart}-${rand}`;

return {
  protocolo,
  cliente: {
    nome: body.nome || 'Cliente não identificado',
    tipo_cliente: body.tipo_cliente || 'condominio',
    responsavel: body.responsavel || body.nome || 'Responsável não identificado',
    whatsapp: body.whatsapp || '',
    email: body.email || '',
    endereco: body.endereco || '',
    bairro: body.bairro || '',
    cidade: body.cidade || 'Rio de Janeiro'
  },
  dados_eletricos: {
    tipo_ligacao: body.tipo_ligacao || 'trifasico',
    tensao: body.tensao || '220/380',
    disjuntor_geral: body.disjuntor_geral || '100',
    padrao_entrada: body.padrao_entrada || 'Muro Light',
    aterramento: !!body.aterramento,
    dr_dps: !!body.dr_dps,
    quadro_cargas_criticas: !!body.quadro_cargas_criticas,
    distancia_inversor_quadro_metros: Number(body.distancia_inversor_quadro) || 10,
    distancia_baterias_quadro_metros: Number(body.distancia_baterias_quadro) || 10
  },
  dados_conta: {
    consumo_mensal_kwh: Number(body.consumo_mensal_kwh) || 1000,
    valor_medio_conta: Number(body.valor_medio_conta) || 1200,
    concessionaria: body.concessionaria || 'Light',
    tarifa: Number(body.tarifa) || 1.15,
    demanda_contratada_kw: Number(body.demanda_contratada_kw) || 0,
    objetivo: body.objetivo || 'hibrido',
    historico_12_meses_kwh: body.historico_12_meses || []
  },
  dados_solares: {
    area_disponivel_m2: Number(body.area_disponivel) || 100,
    tipo_telhado_laje: body.tipo_telhado_laje || 'laje plana',
    sombreamento: body.sombreamento || 'nenhum',
    orientacao: body.orientacao || 'norte',
    inclinacao: body.inclinacao || '15 graus',
    local_inversor: body.local_inversor || 'garagem',
    local_baterias: body.local_baterias || 'garagem',
    ventilacao_adequada: !!body.ventilacao
  },
  cargas_criticas: body.cargas_criticas || [],
  autonomia_desejada_horas: Number(body.autonomia_horas) || 8,
  status: 'recebido',
  compliance_killcritic: {
    status_killcritic: 'BLOQUEADO',
    risco_killcritic: 'baixo',
    motivos_bloqueio: ['Aguardando cálculo e auditoria'],
    pendencias_criticas: []
  }
};
